+    #[test]
+    fn triangular_solve_upper() {
+        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
+        // U = [[2, 1], [0, 3]], b = [5, 6]
+        // Back sub: x1 = 6/3 = 2, x0 = (5 - 1*2)/2 = 1.5
+        let a = s
+            .tensor_variable(vec![2.0, 1.0, 0.0, 3.0], vec![2, 2], false)
